ReplacementChunks.ReplacementContent:
// Update labels
const pEl = document.getElementById('summary-att-present-count');
if (pEl) pEl.innerText = `${present} คน`;
const aEl = document.getElementById('summary-att-absent-count');
if (aEl) aEl.innerText = `${absent} คน`;

// Update bar chart segments (no text inside, purely visual)
const bar = document.getElementById('summary-att-bar');
if (bar) {
    bar.innerHTML = `
        <div class="attendance-bar-segment segment-present" style="width: ${presentPct}%; display: ${presentPct > 0 ? 'block' : 'none'};"></div>
        <div class="attendance-bar-segment segment-absent" style="width: ${absentPct}%; display: ${absentPct > 0 ? 'block' : 'none'};"></div>
    `;
}

